16	
17	package anthropic
18	
19	import (
20		"context"
21		"os"
22		"os/exec"
23		"path/filepath"
24		"slices"
25		"strings"
26		"testing"
27	
28		pkgdispatch "github.com/jsquirrelz/tide/pkg/dispatch"
29	)
30	
31	// fixtureStreamJSON is the canned stream-json content used by the happy-path
32	// test. It mirrors RESEARCH Pattern 5: a system/init, one stream_event delta,
33	// and a final result event with all 4 usage fields.
34	const fixtureStreamJSON = `{"type":"system/init","session_id":"sess-1"}
35	{"type":"stream_event","event":{"type":"content_block_delta","delta":{"type":"text_delta","text":"hi"}}}
36	{"type":"result","result":"hello world","usage":{"input_tokens":100,"output_tokens":50,"cache_read_input_tokens":30,"cache_creation_input_tokens":20},"total_cost_usd":0.001}
37	`
38	
39	// TestRun_VendorMismatch asserts the Anthropic subagent refuses an envelope
40	// whose Provider.Vendor is not "anthropic" — without exec'ing claude. This is
41	// the fail-fast defense per pkg/dispatch/provider.go godoc: image-tag-vs-
42	// envelope drift catches at startup instead of mid-flight.
43	func TestRun_VendorMismatch(t *testing.T) {
44		a := New(Options{
45			ClaudeBinary:  "/nonexistent/claude", // would explode if ever exec'd
46			WorkspaceRoot: t.TempDir(),
47		})
48		in := pkgdispatch.EnvelopeIn{
49			APIVersion: pkgdispatch.APIVersionV1Alpha1,
50			Kind:       pkgdispatch.KindTaskEnvelopeIn,
51			TaskUID:    "uid-vendor-mismatch",
52			Role:       "executor",
53			Level:      "task",
54			Provider: pkgdispatch.ProviderSpec{
55				Vendor: "openai",
56				Model:  "gpt-4",
57			},
58		}
59		_, err := a.Run(context.Background(), in)
60		if err == nil {
61			t.Fatal("expected vendor-mismatch error, got nil")
62		}
63		msg := err.Error()
64		if !strings.Contains(msg, "vendor") || !strings.Contains(msg, "anthropic") {
65			t.Errorf("error should mention vendor and anthropic; got %q", msg)
66		}
67	}
68	
69	// TestRun_UnknownParam asserts Q3 RESOLVED params allow-list — unknown keys
70	// (anything outside {temperature, thinking_budget, top_p, top_k}) cause a
71	// fail-fast error before exec'ing claude. Matches 03-RESEARCH §"Open
72	// Questions Q3 RESOLVED" — reject-unknown at subagent startup.
73	func TestRun_UnknownParam(t *testing.T) {
74		a := New(Options{
75			ClaudeBinary:  "/nonexistent/claude",
76			WorkspaceRoot: t.TempDir(),
77		})
78		in := pkgdispatch.EnvelopeIn{
79			APIVersion: pkgdispatch.APIVersionV1Alpha1,
80			Kind:       pkgdispatch.KindTaskEnvelopeIn,
81			TaskUID:    "uid-bad-param",
82			Role:       "executor",
83			Level:      "task",
84			Provider: pkgdispatch.ProviderSpec{
85				Vendor: "anthropic",
86				Model:  "claude-sonnet-4-6",
87				Params: map[string]string{
88					"unknown_key": "value",
89				},
90			},
91		}
92		_, err := a.Run(context.Background(), in)
93		if err == nil {
94			t.Fatal("expected unknown-param error, got nil")
95		}
96		msg := err.Error()
97		if !strings.Contains(strings.ToLower(msg), "unknown") && !strings.Contains(strings.ToLower(msg), "param") {
98			t.Errorf("error should mention 'unknown' or 'param'; got %q", msg)
99		}
100	}
101	
102	// TestRun_AllowedParams asserts each key in the Q3 allow-list (temperature,
103	// thinking_budget, top_p, top_k) passes the params check. This is a unit-test
104	// negation of TestRun_UnknownParam: with only allowed keys, the params gate
105	// must not fire. We use a fake exec that feeds the fixture stream-json so
106	// the test runs end-to-end without claude on PATH.
107	func TestRun_AllowedParams(t *testing.T) {
108		tmp := t.TempDir()
109		a := newFakeExecAnthropic(t, tmp, fixtureStreamJSON)
110		in := envelopeFixture("uid-allowed-params")
111		in.Provider.Params = map[string]string{
112			"temperature":     "0.7",
113			"thinking_budget": "20000",
114			"top_p":           "0.95",
115			"top_k":           "40",
116		}
117		out, err := a.Run(context.Background(), in)
118		if err != nil {
119			t.Fatalf("Run with allowed params: %v", err)
120		}
121		if out.ExitCode != 0 {
122			t.Errorf("ExitCode: got %d, want 0", out.ExitCode)
123		}
124	}
125	
126	// TestRun_HappyPath asserts the end-to-end exec → stream-json parse →
127	// EnvelopeOut path. Uses a fake exec that runs `bash -c 'cat <fixture>'`
128	// so the test does not depend on the claude CLI being installed.
129	// Validates that:
130	//   - EnvelopeOut.Usage carries the parsed token tally for all 4 fields.
131	//   - EnvelopeOut.Result carries the final assistant text.
132	//   - events.jsonl is written under WorkspaceRoot/envelopes/{TaskUID}/.
133	//   - EnvelopeOut.APIVersion / Kind / TaskUID are set per pkg/dispatch.
134	func TestRun_HappyPath(t *testing.T) {
135		tmp := t.TempDir()
136		a := newFakeExecAnthropic(t, tmp, fixtureStreamJSON)
137		in := envelopeFixture("uid-happy-path")
138		out, err := a.Run(context.Background(), in)
139		if err != nil {
140			t.Fatalf("Run: %v", err)
141		}
142	
143		if out.APIVersion != pkgdispatch.APIVersionV1Alpha1 {
144			t.Errorf("APIVersion: got %q, want %q", out.APIVersion, pkgdispatch.APIVersionV1Alpha1)
145		}
146		if out.Kind != pkgdispatch.KindTaskEnvelopeOut {
147			t.Errorf("Kind: got %q, want %q", out.Kind, pkgdispatch.KindTaskEnvelopeOut)
148		}
149		if out.TaskUID != in.TaskUID {
150			t.Errorf("TaskUID: got %q, want %q", out.TaskUID, in.TaskUID)
151		}
152		if out.ExitCode != 0 {
153			t.Errorf("ExitCode: got %d, want 0", out.ExitCode)
154		}
155		if out.Result != "hello world" {
156			t.Errorf("Result: got %q, want %q", out.Result, "hello world")
157		}
158		if out.Usage.InputTokens != 100 || out.Usage.OutputTokens != 50 {
159			t.Errorf("Usage tokens: got %+v, want In=100 Out=50", out.Usage)
160		}
161		if out.Usage.CacheReadTokens != 30 || out.Usage.CacheCreationTokens != 20 {
162			t.Errorf("Usage cache tokens: got %+v, want CR=30 CC=20", out.Usage)
163		}
164	
165		// events.jsonl must exist under WorkspaceRoot/envelopes/{TaskUID}/
166		eventsPath := filepath.Join(tmp, "envelopes", in.TaskUID, "events.jsonl")
167		data, rerr := os.ReadFile(eventsPath)
168		if rerr != nil {
169			t.Fatalf("events.jsonl not written at %s: %v", eventsPath, rerr)
170		}
171		if !strings.Contains(string(data), `"type":"result"`) {
172			t.Errorf("events.jsonl missing result event; got:\n%s", string(data))
173		}
174	}
175	
176	// TestRun_ExecFailure asserts that when the underlying exec.Cmd exits
177	// non-zero, Run() surfaces a non-zero ExitCode and a populated Reason in
178	// EnvelopeOut. Dispatch-level success vs task-level failure are different
179	// concerns (pkg/dispatch/subagent.go godoc) — we return (EnvelopeOut, nil)
180	// for task failure, not (EnvelopeOut, err).
181	func TestRun_ExecFailure(t *testing.T) {
182		tmp := t.TempDir()
183		a := New(Options{
184			ClaudeBinary:  "/nonexistent/claude", // unused — overridden below
185			WorkspaceRoot: tmp,
186		})
187		// Override execFunc to invoke `false` (always exits 1) — simulates a
188		// claude crash. The harness ParseStream still runs against empty stdout;
189		// the non-zero exit drives ExitCode/Reason.
190		a.execFunc = func(ctx context.Context, name string, args ...string) *exec.Cmd {
191			return exec.CommandContext(ctx, "false")
192		}
193	
194		in := envelopeFixture("uid-exec-fail")
195		out, err := a.Run(context.Background(), in)
196		if err != nil {
197			// Per pkg/dispatch contract, dispatch-level (network/I/O) failures
198			// return non-nil err. exec failing to start IS a dispatch-level fail,
199			// but exit 1 from the CLI is a task-level fail. `false` exits cleanly
200			// non-zero so we expect (out, nil) here with ExitCode != 0.
201			t.Fatalf("Run returned dispatch-level error for task-level fail: %v", err)
202		}
203		if out.ExitCode == 0 {
204			t.Error("expected ExitCode != 0, got 0")
205		}
206		if out.Reason == "" {
207			t.Error("expected non-empty Reason on exec failure")
208		}
209	}
210	
211	// ----------------------------------------------------------------------------
212	// Test helpers
213	// ----------------------------------------------------------------------------
214	
215	// envelopeFixture returns a populated EnvelopeIn for tests that need a
216	// well-formed input. Provider.Vendor is "anthropic" so the vendor fail-fast
217	// does not fire.
218	func envelopeFixture(uid string) pkgdispatch.EnvelopeIn {
219		return pkgdispatch.EnvelopeIn{
220			APIVersion: pkgdispatch.APIVersionV1Alpha1,
221			Kind:       pkgdispatch.KindTaskEnvelopeIn,
222			TaskUID:    uid,
223			Role:       "executor",
224			Level:      "task",
225			Prompt:     "fixture prompt",
226			Provider: pkgdispatch.ProviderSpec{
227				Vendor: "anthropic",
228				Model:  "claude-sonnet-4-6",
229			},
230			ProxyEndpoint: "https://127.0.0.1:8443",
231			SignedToken:   "fixture-signed-token",
232		}
233	}
234	
235	// newFakeExecAnthropic returns an *Anthropic whose execFunc invokes
236	// `bash -c 'cat <fixture-file>'` so the test exercises the parse path
237	// without needing the claude CLI on PATH. The fixture content is written to
238	// a temp file under workspaceRoot.
239	func newFakeExecAnthropic(t *testing.T, workspaceRoot, fixtureContent string) *Anthropic {
240		t.Helper()
241		fixturePath := filepath.Join(workspaceRoot, "fixture.jsonl")
242		if err := os.WriteFile(fixturePath, []byte(fixtureContent), 0o644); err != nil {
243			t.Fatalf("write fixture: %v", err)
244		}
245		a := New(Options{
246			ClaudeBinary:  "/nonexistent/claude", // overridden via execFunc
247			WorkspaceRoot: workspaceRoot,
248		})
249		a.execFunc = func(ctx context.Context, name string, args ...string) *exec.Cmd {
250			// Ignore name/args — we replace them with a deterministic cat-the-fixture.
251			return exec.CommandContext(ctx, "bash", "-c", "cat "+fixturePath)
252		}
253		return a
254	}
255	
256	// TestRun_PromptViaStdinAndPermissionFlags locks in the defect #7 + #8 fixes:
257	//   - #8: the rendered prompt is NOT passed as the `-p` positional argv entry
258	//     (which risks Linux MAX_ARG_STRLEN for large planner prompts) — it is
259	//     delivered via STDIN. So renderedPrompt must be absent from cmd.Args and
260	//     present on cmd.Stdin.
261	//   - #7: the invocation grants the headless Write/Edit capability scoped to
262	//     the per-Task events dir, i.e. `--permission-mode acceptEdits` and
263	//     `--add-dir <eventsDir>` appear in cmd.Args, while `--bare` is retained.
264	//
265	// The fake exec captures the args, drains stdin into a temp file (proving the
266	// prompt was delivered there), then emits the canned stream-json on stdout so
267	// the parse path still completes.
268	func TestRun_PromptViaStdinAndPermissionFlags(t *testing.T) {
269		tmp := t.TempDir()
270	
271		fixturePath := filepath.Join(tmp, "fixture.jsonl")
272		if err := os.WriteFile(fixturePath, []byte(fixtureStreamJSON), 0o644); err != nil {
273			t.Fatalf("write fixture: %v", err)
274		}
275		stdinCapturePath := filepath.Join(tmp, "captured-stdin.txt")
276	
277		a := New(Options{
278			ClaudeBinary:  "/nonexistent/claude", // overridden via execFunc
279			WorkspaceRoot: tmp,
280		})
281	
282		var capturedArgs []string
283		a.execFunc = func(ctx context.Context, name string, args ...string) *exec.Cmd {
284			capturedArgs = append([]string(nil), args...)
285			// Drain stdin -> capture file, then emit the fixture on stdout so the
286			// parser still sees a well-formed stream. Run() sets cmd.Stdin after
287			// this returns, so the spawned shell receives the rendered prompt.
288			script := "cat > " + stdinCapturePath + "; cat " + fixturePath
289			return exec.CommandContext(ctx, "bash", "-c", script)
290		}
291	
292		in := envelopeFixture("uid-stdin-flags")
293		const wantPrompt = "THIS-IS-THE-RENDERED-PROMPT-SENTINEL"
294		in.Prompt = wantPrompt // task executor template echoes nothing structural; sentinel just needs to render
295	
296		out, err := a.Run(context.Background(), in)
297		if err != nil {
298			t.Fatalf("Run: %v", err)
299		}
300		if out.ExitCode != 0 {
301			t.Fatalf("ExitCode: got %d want 0 (reason=%q)", out.ExitCode, out.Reason)
302		}
303	
304		// (a) renderedPrompt must NOT be a positional argv entry. The bare "-p"
305		// flag is present, but no element of Args may carry the prompt sentinel.
306		joined := strings.Join(capturedArgs, "\x00")
307		if strings.Contains(joined, wantPrompt) {
308			t.Errorf("rendered prompt leaked into cmd.Args (defect #8 regression): %v", capturedArgs)
309		}
310		if !containsArg(capturedArgs, "-p") {
311			t.Errorf("expected bare -p flag in args, got %v", capturedArgs)
312		}
313	
314		// (b) the prompt must have been delivered via stdin.
315		stdinData, rerr := os.ReadFile(stdinCapturePath)
316		if rerr != nil {
317			t.Fatalf("read captured stdin: %v", rerr)
318		}
319		if !strings.Contains(string(stdinData), wantPrompt) {
320			t.Errorf("rendered prompt not delivered via stdin; captured=%q", string(stdinData))
321		}
322	
323		// (c) headless write capability flags, scoped to the per-Task events dir,
324		// with --bare retained.
325		wantEventsDir := filepath.Join(tmp, "envelopes", in.TaskUID)
326		assertFlagPair(t, capturedArgs, "--permission-mode", "acceptEdits")
327		assertFlagPair(t, capturedArgs, "--add-dir", wantEventsDir)
328		if !containsArg(capturedArgs, "--bare") {
329			t.Errorf("--bare flag dropped (hermeticity regression): %v", capturedArgs)
330		}
331	}
332	
333	// containsArg reports whether want appears as a standalone element of args.
334	func containsArg(args []string, want string) bool {
335		return slices.Contains(args, want)
336	}
337	
338	// assertFlagPair asserts that flag is immediately followed by value in args.
339	func assertFlagPair(t *testing.T, args []string, flag, value string) {
340		t.Helper()
341		for i, a := range args {
342			if a == flag {
343				if i+1 < len(args) && args[i+1] == value {
344					return
345				}
346				t.Errorf("flag %q present but not followed by %q (args=%v)", flag, value, args)
347				return
348			}
349		}
350		t.Errorf("flag %q missing from args=%v", flag, args)
351	}
352	
353	// writeChildPromptJSON writes a prompt artifact in the children JSON format at
354	// the given path. The artifact matches childPromptFile: {"spec":{"prompt":"<p>"}}.
355	func writeChildPromptJSON(t *testing.T, path, prompt string) {
356		t.Helper()
357		data := []byte(`{"kind":"Task","name":"task-01","spec":{"prompt":"` + prompt + `"}}`)
358		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
359			t.Fatalf("mkdir for prompt artifact: %v", err)
360		}
361		if err := os.WriteFile(path, data, 0o644); err != nil {
362			t.Fatalf("write prompt artifact: %v", err)
363		}
364	}
365	
366	// TestPromptPath_HappyPath asserts that when in.PromptPath is set and the artifact
367	// exists under WorkspaceRoot, Run reads the artifact and renders {{.Prompt}} from it.
368	func TestPromptPath_HappyPath(t *testing.T) {
369		tmp := t.TempDir()
370		const wantPrompt = "implement FormattedNow as specified"
371	
372		// Write the prompt artifact at <WorkspaceRoot>/envelopes/planner-uid/children/task-01.json
373		artifactPath := filepath.Join(tmp, "envelopes", "planner-uid", "children", "task-01.json")
374		writeChildPromptJSON(t, artifactPath, wantPrompt)
375	
376		stdinCapturePath := filepath.Join(tmp, "captured-stdin.txt")
377		fixturePath := filepath.Join(tmp, "fixture.jsonl")
378		if err := os.WriteFile(fixturePath, []byte(fixtureStreamJSON), 0o644); err != nil {
379			t.Fatalf("write fixture: %v", err)
380		}
381	
382		a := New(Options{
383			ClaudeBinary:  "/nonexistent/claude",
384			WorkspaceRoot: tmp,
385		})
386		// Capture stdin so we can verify the prompt was populated from the artifact.
387		script := "cat > " + stdinCapturePath + "; cat " + fixturePath
388		a.execFunc = func(ctx context.Context, name string, args ...string) *exec.Cmd {
389			return exec.CommandContext(ctx, "bash", "-c", script)
390		}
391	
392		in := envelopeFixture("uid-promptpath-happy")
393		in.Prompt = ""                                                // empty — must be populated from PromptPath
394		in.PromptPath = "envelopes/planner-uid/children/task-01.json" // workspace-relative
395	
396		out, err := a.Run(context.Background(), in)
397		if err != nil {
398			t.Fatalf("Run: %v", err)
399		}
400		if out.ExitCode != 0 {
401			t.Fatalf("ExitCode: got %d want 0 (reason=%q)", out.ExitCode, out.Reason)
402		}
403		// The artifact's .spec.prompt must have been delivered via stdin.
404		stdinData, rerr := os.ReadFile(stdinCapturePath)
405		if rerr != nil {
406			t.Fatalf("read captured stdin: %v", rerr)
407		}
408		if !strings.Contains(string(stdinData), wantPrompt) {
409			t.Errorf("artifact prompt not delivered via stdin; captured=%q", string(stdinData))
410		}
411	}
412	
413	// TestPromptPath_AbsoluteRejected asserts that an absolute PromptPath is rejected
414	// before any file read (traversal defense T-09-05).
415	func TestPromptPath_AbsoluteRejected(t *testing.T) {
416		a := New(Options{
417			ClaudeBinary:  "/nonexistent/claude",
418			WorkspaceRoot: t.TempDir(),
419		})
420		in := envelopeFixture("uid-abs")
421		in.Prompt = ""
422		in.PromptPath = "/etc/passwd"
423	
424		_, err := a.Run(context.Background(), in)
425		if err == nil {
426			t.Fatal("want error for absolute PromptPath, got nil")
427		}
428		if !strings.Contains(err.Error(), "absolute") {
429			t.Errorf("error should mention 'absolute'; got %q", err.Error())
430		}
431	}
432	
433	// TestPromptPath_TraversalRejected asserts that a "../escape" PromptPath is
434	// rejected (traversal defense T-09-05).
435	func TestPromptPath_TraversalRejected(t *testing.T) {
436		a := New(Options{
437			ClaudeBinary:  "/nonexistent/claude",
438			WorkspaceRoot: t.TempDir(),
439		})
440		in := envelopeFixture("uid-traversal")
441		in.Prompt = ""
442		in.PromptPath = "../../../../etc/passwd"
443	
444		_, err := a.Run(context.Background(), in)
445		if err == nil {
446			t.Fatal("want error for traversal PromptPath, got nil")
447		}
448		if !strings.Contains(err.Error(), "..") && !strings.Contains(err.Error(), "traversal") && !strings.Contains(err.Error(), "workspace") {
449			t.Errorf("error should indicate traversal rejection; got %q", err.Error())
450		}
451	}
452	
453	// TestPromptPath_OutsideRootRejected asserts that a resolved path outside
454	// WorkspaceRoot is rejected (second-line traversal defense).
455	func TestPromptPath_OutsideRootRejected(t *testing.T) {
456		tmp := t.TempDir()
457		a := New(Options{
458			ClaudeBinary:  "/nonexistent/claude",
459			WorkspaceRoot: filepath.Join(tmp, "workspace"),
460		})
461		in := envelopeFixture("uid-outside")
462		in.Prompt = ""
463		// A clean relative path that happens to resolve outside the workspace root
464		// because WorkspaceRoot is a sub-dir of tmp: sibling/ escapes workspace/.
465		in.PromptPath = "../sibling/evil.json"
466	
467		_, err := a.Run(context.Background(), in)
468		if err == nil {
469			t.Fatal("want error for out-of-root PromptPath, got nil")
470		}
471	}
472	
473	// TestPromptPath_EmptySpecPromptRejected asserts that an artifact with an
474	// empty .spec.prompt causes a hard error (no silent empty-prompt dispatch, #4 class).
475	func TestPromptPath_EmptySpecPromptRejected(t *testing.T) {
476		tmp := t.TempDir()
477		// Write artifact with empty spec.prompt.
478		artifactPath := filepath.Join(tmp, "envelopes", "empty", "task.json")
479		if err := os.MkdirAll(filepath.Dir(artifactPath), 0o755); err != nil {
480			t.Fatalf("mkdir: %v", err)
481		}
482		if err := os.WriteFile(artifactPath, []byte(`{"spec":{"prompt":""}}`), 0o644); err != nil {
483			t.Fatalf("write artifact: %v", err)
484		}
485	
486		a := New(Options{
487			ClaudeBinary:  "/nonexistent/claude",
488			WorkspaceRoot: tmp,
489		})
490		in := envelopeFixture("uid-emptyspec")
491		in.Prompt = ""
492		in.PromptPath = "envelopes/empty/task.json"
493	
494		_, err := a.Run(context.Background(), in)
495		if err == nil {
496			t.Fatal("want error for empty .spec.prompt, got nil")
497		}
498		if !strings.Contains(err.Error(), "empty") {
499			t.Errorf("error should mention 'empty'; got %q", err.Error())
500		}
501	}
502	
503	// TestPromptPath_EmptyPath_PlannerPath asserts that when PromptPath is empty
504	// and Prompt is non-empty (planner path), Run uses in.Prompt unchanged.
505	func TestPromptPath_EmptyPath_PlannerPath(t *testing.T) {
506		tmp := t.TempDir()
507		fixturePath := filepath.Join(tmp, "fixture.jsonl")
508		if err := os.WriteFile(fixturePath, []byte(fixtureStreamJSON), 0o644); err != nil {
509			t.Fatalf("write fixture: %v", err)
510		}
511		stdinCapturePath := filepath.Join(tmp, "stdin.txt")
512	
513		a := New(Options{
514			ClaudeBinary:  "/nonexistent/claude",
515			WorkspaceRoot: tmp,
516		})
517		script := "cat > " + stdinCapturePath + "; cat " + fixturePath
518		a.execFunc = func(ctx context.Context, name string, args ...string) *exec.Cmd {
519			return exec.CommandContext(ctx, "bash", "-c", script)
520		}
521	
522		const plannerPrompt = "PLANNER-OUTCOME-SENTINEL"
523		in := envelopeFixture("uid-planner-path")
