525		in.PromptPath = "" // planner path: PromptPath empty, Prompt set directly
526	
527		out, err := a.Run(context.Background(), in)
528		if err != nil {
529			t.Fatalf("Run: %v", err)
530		}
531		if out.ExitCode != 0 {
532			t.Fatalf("ExitCode: got %d want 0", out.ExitCode)
533		}
534		stdinData, rerr := os.ReadFile(stdinCapturePath)
535		if rerr != nil {
